function CrudForm<D extends DataModel>(props: CrudFormProps<D>) {
  const { formState, onFieldChange, onSubmit, onReset, submitButtonLabel, slots, slotProps } =
    props;

  const formValues = formState.values;
  const formErrors = formState.errors;

  const crudContext = React.useContext(CrudContext);
  const dataSource = (props.dataSource ?? crudContext.dataSource) as NonNullable<
    typeof props.dataSource
  >;

  invariant(dataSource, 'No data source found.');

  const { fields } = dataSource;

  const [isSubmitting, setIsSubmitting] = React.useState(false);

  const handleSubmit = React.useCallback(
    async (event: React.FormEvent<HTMLFormElement>) => {
      event.preventDefault();

      setIsSubmitting(true);
      try {
        await onSubmit(formValues);
      } finally {
        setIsSubmitting(false);
      }
    },
    [formValues, onSubmit],
  );

  const handleTextFieldChange = React.useCallback(
    (event: React.ChangeEvent<HTMLInputElement>) => {
      onFieldChange(event.target.name, event.target.value);
    },
    [onFieldChange],
  );

  const handleNumberFieldChange = React.useCallback(
    (event: React.ChangeEvent<HTMLInputElement>) => {
      onFieldChange(event.target.name, Number(event.target.value));
    },
    [onFieldChange],
  );

  const handleCheckboxFieldChange = React.useCallback(
    (event: React.ChangeEvent<HTMLInputElement>, checked: boolean) => {
      onFieldChange(event.target.name, checked);
    },
    [onFieldChange],
  );

  const handleDateFieldChange = React.useCallback(
    (name: string) => (value: Dayjs | null) => {
      if (value?.isValid()) {
        onFieldChange(name, value.toISOString() ?? null);
      } else if (formValues[name]) {
        onFieldChange(name, null);
      }
    },
    [formValues, onFieldChange],
  );

  const handleSelectFieldChange = React.useCallback(
    (event: SelectChangeEvent) => {
      onFieldChange(event.target.name, event.target.value);
    },
    [onFieldChange],
  );

  const renderField = React.useCallback(
    (formField: DataField) => {
      const { field, type, headerName, renderFormField } = formField;

      const fieldValue = formValues[field];
      const fieldError = formErrors[field];

      let fieldElement: React.ReactNode = null;

      if (renderFormField) {
        fieldElement = renderFormField({
          value: (fieldValue ?? null) as DataFieldFormValue,
          onChange: (value) => onFieldChange(field, value),
          error: fieldError ?? null,
        });
      } else if (!type || type === 'string') {
        const TextFieldComponent = slots?.textField ?? TextField;

        fieldElement = (
          <TextFieldComponent
            value={fieldValue ?? ''}
            onChange={handleTextFieldChange}
            name={field}
            label={headerName}
            error={!!fieldError}
            helperText={fieldError ?? ' '}
            fullWidth
            {...slotProps?.textField}
          />
        );
      } else if (type === 'number') {
        const TextFieldComponent = slots?.textField ?? TextField;

        fieldElement = (
          <TextFieldComponent
            value={fieldValue ?? ''}
            onChange={handleNumberFieldChange}
            name={field}
            type="number"
            label={headerName}
            error={!!fieldError}
            helperText={fieldError ?? ' '}
            fullWidth
            {...slotProps?.textField}
          />
        );
      } else if (type === 'boolean') {
        const CheckBoxComponent = slots?.checkbox ?? Checkbox;

        fieldElement = (
          <FormControl>
            <FormControlLabel
              name={field}
              control={
                <CheckBoxComponent
                  size="large"
                  checked={fieldValue as boolean}
                  onChange={handleCheckboxFieldChange}
                  {...slotProps?.checkbox}
                />
              }
              label={headerName}
            />
            <FormHelperText error={!!fieldError}>{fieldError ?? ' '}</FormHelperText>
          </FormControl>
        );
      } else if (type === 'date') {
        const DatePickerComponent = slots?.datePicker ?? DatePicker;

        fieldElement = (
          <LocalizationProvider dateAdapter={AdapterDayjs}>
            <DatePickerComponent
              value={fieldValue ? dayjs(fieldValue as string) : null}
              onChange={handleDateFieldChange(field)}
              name={field}
              label={headerName}
              slotProps={{
                textField: {
                  error: !!fieldError,
                  helperText: fieldError ?? ' ',
                  fullWidth: true,
                },
              }}
              {...slotProps?.datePicker}
            />
          </LocalizationProvider>
        );
      } else if (type === 'dateTime') {
        const DateTimePickerComponent = slots?.dateTimePicker ?? DateTimePicker;

        fieldElement = (
          <LocalizationProvider dateAdapter={AdapterDayjs}>
            <DateTimePickerComponent
              value={fieldValue ? dayjs(fieldValue as string) : null}
              onChange={handleDateFieldChange(field)}
              name={field}
              label={headerName}
              slotProps={{
                textField: {
                  error: !!fieldError,
                  helperText: fieldError ?? ' ',
                  fullWidth: true,
                },
              }}
              {...slotProps?.dateTimePicker}
            />
          </LocalizationProvider>
        );
      } else if (type === 'singleSelect') {
        const SelectComponent = slots?.select ?? Select;

        const { getOptionValue, getOptionLabel, valueOptions } =
          formField as GridSingleSelectColDef;

        if (valueOptions && Array.isArray(valueOptions)) {
          const labelId = `${field}-label`;

          fieldElement = (
            <FormControl error={!!fieldError} fullWidth>
              <InputLabel id={labelId}>{headerName}</InputLabel>
              <SelectComponent
                value={(fieldValue as string) ?? ''}
                onChange={handleSelectFieldChange as SelectProps['onChange']}
                labelId={labelId}
                name={field}
                label={headerName}
                defaultValue=""
                fullWidth
                {...slotProps?.select}
              >
                {valueOptions.map((option) => {
                  let optionValue: string | number = option as string | number;
                  let optionLabel: string | number = option as string | number;
                  if (typeof option !== 'string' && typeof option !== 'number') {
                    optionValue = getOptionValue ? getOptionValue(option) : option.value;
                    optionLabel = getOptionLabel ? getOptionLabel(option) : option.label;
                  }

                  return (
                    <MenuItem key={optionValue} value={optionValue}>
                      {optionLabel}
                    </MenuItem>
                  );
                })}
              </SelectComponent>
              <FormHelperText>{fieldError ?? ' '}</FormHelperText>
            </FormControl>
          );
        }
      }

      return (
        <Grid key={field} size={{ xs: 12, sm: 6 }} sx={{ display: 'flex' }}>
          {fieldElement}
        </Grid>
      );
    },
    [
      formErrors,
      formValues,
      handleCheckboxFieldChange,
      handleDateFieldChange,
      handleNumberFieldChange,
      handleSelectFieldChange,
      handleTextFieldChange,
      onFieldChange,
      slotProps,
      slots,
    ],
  );

  const handleReset = React.useCallback(async () => {
    if (onReset) {
      await onReset(formValues);
    }
  }, [formValues, onReset]);

  return (
    <Box
      component="form"
      onSubmit={handleSubmit}
      noValidate
      autoComplete="off"
      onReset={handleReset}
      sx={{ width: '100%' }}
    >
      <FormGroup>
        <Grid container spacing={2} sx={{ mb: 2, width: '100%' }}>
          {fields
            .filter(({ field, editable }) => field !== 'id' && editable !== false)
            .map(renderField)}
        </Grid>
      </FormGroup>
      <Box sx={{ display: 'flex', justifyContent: 'flex-end' }}>
        <Button type="submit" variant="contained" size="large" loading={isSubmitting}>
          {submitButtonLabel}
        </Button>
      </Box>
    </Box>
  );
}

function NotificationsProvider(props: NotificationsProviderProps) {
  const { children } = props;
  const [state, setState] = React.useState<NotificationsState>({ queue: [] });

  const show = React.useCallback<ShowNotification>((message, options = {}) => {
    const notificationKey = options.key ?? `::toolpad-internal::notification::${generateId()}`;
    setState((prev) => {
      if (prev.queue.some((n) => n.notificationKey === notificationKey)) {
        // deduplicate by key
        return prev;
      }
      return {
        ...prev,
        queue: [...prev.queue, { message, options, notificationKey, open: true }],
      };
    });
    return notificationKey;
  }, []);

  const close = React.useCallback<CloseNotification>((key) => {
    setState((prev) => ({
      ...prev,
      queue: prev.queue.filter((n) => n.notificationKey !== key),
    }));
  }, []);

  const contextValue = React.useMemo(() => ({ show, close }), [show, close]);

  return (
    <RootPropsContext.Provider value={props}>
      <NotificationsContext.Provider value={contextValue}>
        {children}
        <Notifications state={state} />
      </NotificationsContext.Provider>
    </RootPropsContext.Provider>
  );
}

